sys_script.script:
(function executeRule(current, previous /*null when async*/) {

    // ================================
    // 1. Check Lookup Rule Dependency
    // ================================
    var lookupRule = new GlideRecord('x_ctans_incentnow_lookup_rule');
    lookupRule.addQuery('input_type', 'earning_rule');
    lookupRule.addQuery('select_earning_rule', current.sys_id);
    lookupRule.query();

    if (lookupRule.next()) {
        gs.addErrorMessage(
            "Cannot delete. This earning rule is used in lookup rule: " +
            lookupRule.display_name
        );
        current.setAbortAction(true);
        return;
    }

    // ================================
    // 2. Check Payout Summary - Input 1
    // ================================
    var payout1 = new GlideRecord('x_ctans_incentnow_payout_summary');
    payout1.addQuery('input1_type', 'earning_rule');
    payout1.addQuery('input1_earning_rule', current.sys_id);
    payout1.query();

    if (payout1.next()) {
        gs.addErrorMessage(
            "Cannot delete. Used in payout rule (Input 1): " +
            payout1.rule_name
        );
        current.setAbortAction(true);
        return;
    }

    // ================================
    // 3. Check Payout Summary - Input 2
    // ================================
    var payout2 = new GlideRecord('x_ctans_incentnow_payout_summary');
    payout2.addQuery('input2_type', 'earning_rule');
    payout2.addQuery('input2_earning_rule', current.sys_id);
    payout2.query();

    if (payout2.next()) {
        gs.addErrorMessage(
            "Cannot delete. Used in payout rule (Input 2): " +
            payout2.rule_name
        );
        current.setAbortAction(true);
        return;
    }

})(current, previous);
